set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<title>Real Bank - Account Not Found</title>

<style>
*{
margin:0;
padding:0;
box-sizing:border-box;
font-family:'Segoe UI',Arial,sans-serif;
}

body{
background:#edf2f7;
padding:30px;
color:#333;
}

.wrapper{
max-width:760px;
margin:auto;
background:#fff;
border-radius:18px;
overflow:hidden;
box-shadow:0 15px 35px rgba(0,0,0,.15);
}

.header{
background:linear-gradient(135deg,#8B0000,#C62828,#E53935);
padding:40px;
text-align:center;
color:#fff;
}

.logo{
font-size:36px;
font-weight:bold;
}

.tagline{
margin-top:8px;
font-size:15px;
opacity:.9;
}

.hero{
padding:35px;
background:#FFF5F5;
text-align:center;
}

.hero h2{
color:#C62828;
font-size:30px;
margin-bottom:15px;
}

.hero p{
font-size:15px;
line-height:28px;
color:#666;
}

.alert{
margin:25px;
padding:20px;
background:#FDECEC;
border-left:6px solid #D32F2F;
border-radius:10px;
color:#B71C1C;
font-size:17px;
font-weight:bold;
text-align:center;
}

.card{
margin:30px;
border:1px solid #E5E5E5;
border-radius:15px;
overflow:hidden;
}

.card-title{
background:#C62828;
color:#fff;
padding:18px;
font-size:20px;
font-weight:bold;
}

table{
width:100%;
border-collapse:collapse;
}

td{
padding:16px;
border-bottom:1px solid #EEEEEE;
}

td:first-child{
background:#FAFAFA;
font-weight:bold;
width:40%;
color:#555;
}

.status{
background:#FDECEC;
color:#C62828;
padding:6px 15px;
border-radius:25px;
font-weight:bold;
display:inline-block;
}

.acc{
font-size:22px;
font-weight:bold;
color:#0056B3;
}

.info{
margin:30px;
padding:22px;
background:#FFF8E8;
border-left:6px solid #F59E0B;
border-radius:10px;
}

.info h3{
margin-bottom:15px;
color:#B45309;
}

.info ul{
padding-left:20px;
}

.info li{
margin-bottom:10px;
line-height:24px;
}

.footer{
background:#002B5B;
color:#fff;
padding:35px;
text-align:center;
font-size:13px;
line-height:24px;
}

.support{
margin-top:20px;
padding-top:20px;
border-top:1px solid rgba(255,255,255,.2);
}
</style>

</head>

<body>

<div class='wrapper'>

<div class='header'>

<div class='logo'>
🏦 REAL BANK
</div>

<div class='tagline'>
Safe • Secure • Trusted Banking
</div>

</div>

<div class='hero'>

<h2>
❌ Account Verification Failed
</h2>

<p>

We could not locate any account associated with the customer details you provided.

Please verify your information and try again.

</p>

</div>

<div class='alert'>

⚠ No account was found with the provided customer details.

</div>

<div class='card'>

<div class='card-title'>

📄 Verification Summary

</div>

<table>

<tr>
<td>Status</td>
<td><span class='status'>FAILED</span></td>
</tr>

<tr>
<td>Status Code</td>
<td>404</td>
</tr>

<tr>
<td>Account Number</td>
<td class='acc'>" ++ ((vars.accountNumber default "Unknown") as String) ++ "</td>
</tr>

<tr>
<td>Message</td>
<td>
An account does not exist with the provided customer details.
Please verify your information or register as a new customer if you do not already have an account.
</td>
</tr>

</table>

</div>

<div class='info'>

<h3>
💡 What You Can Do
</h3>

<ul>

<li>Verify that the Account Number is correct.</li>

<li>Check your registered Email Address and Aadhaar Number.</li>

<li>If you are a new customer, please create a new account.</li>

<li>If you believe this is an error, contact Real Bank Customer Support.</li>

</ul>

</div>

<div class='footer'>

<b>Thank You For Banking With Real Bank ❤️</b>

<br><br>

Customer Care : +91 9494207062

<br>

Email : narsingbeesetti22@gmail.com

<br><br>

© 2026 Real Bank

<br>

Safe Banking | Digital Banking | Secure Transactions

<div class='support'>

This is an automated email. Please do not reply.

</div>

</div>

</div>

</body>

</html>"]
